 3→import com.exam.dto.Result;
 4→import lombok.extern.slf4j.Slf4j;
 5→import org.springframework.validation.FieldError;
 6→import org.springframework.web.bind.MethodArgumentNotValidException;
 7→import org.springframework.web.bind.annotation.ExceptionHandler;
 8→import org.springframework.web.bind.annotation.RestControllerAdvice;
 9→
10→/**
11→ * 全局异常处理器
12→ */
13→@Slf4j
14→@RestControllerAdvice
15→public class GlobalExceptionHandler {
16→
17→    @ExceptionHandler(BizException.class)
18→    public Result<?> handleBizException(BizException e) {
19→        log.warn("[lbl][Exception][BIZ] 业务异常, code={}, message={}", e.getErrorCode().getCode(), e.getMessage());
20→        return Result.fail(e.getErrorCode());
21→    }
22→
23→    @ExceptionHandler(MethodArgumentNotValidException.class)
24→    public Result<?> handleValidationException(MethodArgumentNotValidException e) {
25→        FieldError fieldError = e.getBindingResult().getFieldError();
26→        String errorMessage = fieldError != null ? fieldError.getDefaultMessage() : "请求参数错误";
27→        log.warn("[lbl][Exception][VALIDATION] 参数校验失败, message={}", errorMessage);
28→        return Result.fail(400, errorMessage);
29→    }
30→
31→    @ExceptionHandler(Exception.class)
32→    public Result<?> handleException(Exception e) {
33→        log.error("[lbl][Exception][SYSTEM] 系统内部异常", e);
34→        return Result.fail(ErrorCode.INTERNAL_ERROR);
35→    }
36→}
